function LoadHelpers()
	for i = 1, #HELPER_CONFIG do
		local config = HELPER_CONFIG[i]
		SetHelper(config.ItemIndex, config.Type, config.SeparateModel, config.Movement, config.DefenseSkill, config.Height, config.Size, config.SizeSelectChar, config.Miniature,config.SizeMiniature, config.VelocityMiniature, config.ModelDir, config.Model, config.ObjectModelDir, config.ObjectModel, config.FileType)
	end
end

function MoveEffects(BMDStruct, ObjectStruct, Type, Miniature)
	local Bmd = BMD.new(BMDStruct)
	local Obj = Object.new(ObjectStruct)

	if Miniature == 1 then
		for i = 1, #HELPER_CONFIG do
			local config = HELPER_CONFIG[i]

			if config.ItemIndex == Type or CheckModelById(config.ItemIndex) == Type then
				local helperEffect = RENDER_HELPER[config.ItemIndex]

				if helperEffect ~= nil then
					local helperEffect = RENDER_HELPER[config.ItemIndex].Miniature
					for v = 1, #helperEffect do
						local effect = helperEffect[v]

						local black = 0
						if effect.Black then black = 1 end

						for _, action in ipairs(effect.Actions) do
							if action == -1 or action == Obj:getAction() then
								if (effect.EffectType == 0) then
									Bmd:TransformPosition(effect.Bone, effect.PosX, effect.PosY, effect.PosZ)
									Bmd:CreateSprite(effect.EffectIndex, effect.Size, effect.R, effect.G, effect.B, ObjectStruct, black)
								elseif (effect.EffectType == 1) then
									Bmd:TransformPosition(effect.Bone, effect.PosX, effect.PosY, effect.PosZ)
									Bmd:CreateParticle(effect.EffectIndex, effect.EffectLevel, effect.Size, effect.R, effect.G, effect.B, ObjectStruct)
								elseif (effect.EffectType == 2) then
									Bmd:TransformPosition(effect.Bone, effect.PosX, effect.PosY, effect.PosZ)
									Bmd:CreateEffect(effect.EffectIndex, effect.EffectLevel, effect.R, effect.G, effect.B, ObjectStruct)
								end
							end
						end
					end
				end

				Bmd = nil
				Obj = nil
				break
			end
		end
	else
		for i = 1, #HELPER_CONFIG do
			local config = HELPER_CONFIG[i]

			if config.ItemIndex == Type or CheckModelById(config.ItemIndex) == Type then
				local helperEffect = RENDER_HELPER[config.ItemIndex]

				if helperEffect ~= nil then
					local helperEffect = RENDER_HELPER[config.ItemIndex].Effect
					for v = 1, #helperEffect do
						local effect = helperEffect[v]

						local black = 0
						if effect.Black then black = 1 end

						for _, action in ipairs(effect.Actions) do
							if action == -1 or action == Obj:getAction() then
								if (effect.EffectType == 0) then
									Bmd:TransformPosition(effect.Bone, effect.PosX, effect.PosY, effect.PosZ)
									Bmd:CreateSprite(effect.EffectIndex, effect.Size, effect.R, effect.G, effect.B, ObjectStruct, black)
								elseif (effect.EffectType == 1) then
									Bmd:TransformPosition(effect.Bone, effect.PosX, effect.PosY, effect.PosZ)
									Bmd:CreateParticle(effect.EffectIndex, effect.EffectLevel, effect.Size, effect.R, effect.G, effect.B, ObjectStruct)
								elseif (effect.EffectType == 2) then
									Bmd:TransformPosition(effect.Bone, effect.PosX, effect.PosY, effect.PosZ)
									Bmd:CreateEffect(effect.EffectIndex, effect.EffectLevel, effect.R, effect.G, effect.B, ObjectStruct)
								end
							end
						end
					end
				end

				Bmd = nil
				Obj = nil
				break
			end
		end
	end

	Bmd = nil
	Obj = nil
end

function RenderHelper(BMDStruct, ObjectStruct, Type)
	for i = 1, #HELPER_CONFIG do
		local config = HELPER_CONFIG[i]

		if config.ItemIndex == Type or CheckModelById(config.ItemIndex) == Type then
			if config.Type == 0
			then
				CreateFly(BMDStruct, ObjectStruct, config.ItemIndex)
				return
			elseif config.Type == 1 then
				CreateUniria(BMDStruct, ObjectStruct, config.ItemIndex)
				return
			elseif config.Type == 2 then
				CreateDinorant(BMDStruct, ObjectStruct, config.ItemIndex)
				return
			elseif config.Type == 3 then
				CreateFenrir(BMDStruct, ObjectStruct, config.ItemIndex)
				return
			elseif config.Type == 4 then
				CreateHorse(BMDStruct, ObjectStruct, config.ItemIndex)
				return
			elseif config.Type == 5 then
				CreateDragon(BMDStruct, ObjectStruct, config.ItemIndex)
				return
			end
			break
		end
	end
end

function CreateFly(BMDStruct, ObjectStruct, Type)
	local Bmd = BMD.new(BMDStruct)
	local Obj = Object.new(ObjectStruct)

	Bmd:BeginRender(1.0)
	Bmd:setMesh(0)

	--RENDER
	local helperGlow = RENDER_HELPER[Type]

	if helperGlow ~= nil then
		helperGlow = RENDER_HELPER[Type].Model
		for i = 1, #helperGlow do
			local glow = helperGlow[i]

			math.randomseed(os.time())

			local randValue = 100
			local action = Obj:getAction()

			if glow.Timer ~= 100 then
				randValue = math.random(1, 100)
			end

			if glow.Timer >= randValue then
				if glow.R ~= -1 and glow.G ~= -1 and glow.B ~= -1 then
					Bmd:SetLight(glow.R, glow.G, glow.B)
				end
				Bmd:glColor3fv()

				for _, action in ipairs(glow.Actions) do
					if action == -1 or action == Obj:getAction() then
						if glow.Render then
							if glow.Effect == 0 then --EFEITO RENDER (PISCA PISCA)
								local Vertex = GetDoubleRender(glow.RenSpeed, 0.0) + glow.RenOpacity
								if Vertex > glow.RenColor
								then
									Vertex = glow.RenColor
								end

								if glow.Color then
									if glow.R ~= -1 then
										Bmd:SetLight(glow.RR, Vertex, Vertex)
									end
									if glow.G ~= -1 then
										Bmd:SetLight(Vertex, glow.RG, Vertex)
									end
									if glow.B ~= -1 then
										Bmd:SetLight(Vertex, Vertex, glow.RB)
									end
								else
									Bmd:SetLight(Vertex, Vertex, Vertex)
								end

								Bmd:glColor3fv()
								if (glow.Glow ~= 66) then
										Bmd:setMesh(glow.Mesh)
								end
								Bmd:RenderMesh(glow.Mesh, glow.Glow, Obj:Alpha(), Obj:Mesh(), Obj:Light(), Obj:TexCoordU(), Obj:TexCoordV(), glow.Texture)
							else
								local AnyTex = worldTime()
								local TexCoordV = Obj:TexCoordV()
								local TexCoordU = Obj:TexCoordU()

								if glow.Effect == 1 then TexCoordV = AnyTex / 100 * glow.RenSpeed end
								if glow.Effect == 2 then TexCoordV = AnyTex / 100 * -glow.RenSpeed end
								if glow.Effect == 3 then TexCoordU = AnyTex / 100 * glow.RenSpeed end
								if glow.Effect == 4 then TexCoordU = AnyTex / 100 * -glow.RenSpeed end
								if glow.Effect == 5 then
									TexCoordU = (math.floor((AnyTex % (15 * 40) / 40) % 4)) * glow.RenSpeed
									TexCoordV = (math.floor((AnyTex % (15 * 40) / 40) / 4)) * glow.RenSpeed
								end
								if glow.Effect == 6 then
									TexCoordU = (math.floor((AnyTex % (15 * 40) / 40) % 4)) * -glow.RenSpeed
									TexCoordV = (math.floor((AnyTex % (15 * 40) / 40) / 4)) * -glow.RenSpeed
								end

								if glow.FixEffect then
									Bmd:SetLight(0.0, 0.0, 0.0)
									Bmd:glColor3fv()
									Bmd:setMesh(glow.Mesh)
									Bmd:RenderMesh(glow.Mesh, 1, Obj:Alpha(), glow.Mesh, Obj:Light(), Obj:TexCoordU(), Obj:TexCoordV(), glow.Texture)
								end

								if glow.R ~= -1 and glow.G ~= -1 and glow.B ~= -1 then
									Bmd:SetLight(glow.R, glow.G, glow.B)
								end
								Bmd:glColor3fv()

								for c = 1, glow.Value do
									Bmd:glColor3fv()
									if (glow.Glow ~= 66) then
											Bmd:setMesh(glow.Mesh)
									end
									Bmd:RenderMesh(glow.Mesh, glow.Glow, Obj:Alpha(), glow.Mesh, Obj:Light(), TexCoordU, TexCoordV, glow.Texture)
								end
							end
						else
							Bmd:glColor3fv()
							if (glow.Glow ~= 66) then
								Bmd:setMesh(glow.Mesh)
							end
							Bmd:RenderMesh(glow.Mesh, glow.Glow, Obj:Alpha(), Obj:Mesh(), Obj:Light(), Obj:TexCoordU(), Obj:TexCoordV(), glow.Texture)
						end
					end
				end
			end

			if glow.Shadow then
				--Bmd:RenderShadowModel()
				--ou
				Bmd:SetLight(0.0, 0.0, 0.0)
				Bmd:glColor3fv()
				Bmd:setMesh(glow.Mesh)
				Bmd:RenderMesh(glow.Mesh, 1185, 0.9, Obj:Mesh(), Obj:Light(), Obj:TexCoordU(), Obj:TexCoordV(), -1) --OPACIDADE DO ALPHA 0.9
			end
		end

		--SOMBRA
		if RENDER_HELPER[Type].Shadow then
			Bmd:RenderShadowModel()
		end

		--PEGADAS NO CHÃO
		if RENDER_HELPER[Type].FootEffect ~= nil then
			local pegada = RENDER_HELPER[Type].FootEffect
			for i in ipairs(pegada) do
				if pegada[i].Enabled then
					Bmd:CreateEffectsInFenrirUsingSkill(ObjectStruct, pegada[i].R, pegada[i].G, pegada[i].B, pegada[i].EffectID, pegada[i].EffectLevel, pegada[i].EffectType, pegada[i].Size, pegada[i].FrontLeft, pegada[i].FrontRight, pegada[i].BackLeft, pegada[i].BackRight)
				end
			end
		end
	else
		Bmd:glColor3fv()
		Bmd:RenderBody(2, Obj:Alpha(), Obj:Mesh(), Obj:Light(), Obj:TexCoordU(), Obj:TexCoordV(), Obj:Hidden(), -1)
	end

	Bmd:setMesh(-1)
	Bmd:EndRender()

	Bmd = nil
	Obj = nil
	collectgarbage()
end

